css_snippet:
:root {
  --bg: #0a0a0a;
  --surface: #141414;
  --text: #f0ece4;
  --text-muted: #8a8680;
  --accent: #c9a96e;
  --border: rgba(255,255,255,0.08);

  --font-h: 'Playfair Display', Georgia, serif;
  --font-b: 'Inter', Helvetica, sans-serif;

  --space-section: clamp(80px, 10vw, 140px);
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-b);
  font-weight: 300;
  letter-spacing: -0.01em;
}

h1, h2, h3 {
  font-family: var(--font-h);
  font-weight: 300;
  letter-spacing: 0.05em;
  line-height: 1.15;
}
